// reactapp/src/components/DoctorDashboard.js
import React, { useEffect, useState } from "react";
import * as api from "../utils/api";

export default function DoctorDashboard() {
  const [appointments, setAppointments] = useState([]);
  const [loading, setLoading] = useState(true);
  const u = JSON.parse(localStorage.getItem("user") || "null");

  useEffect(() => {
    let mounted = true;
    if (!u || u.role !== "DOCTOR") { window.location.href = "/login"; return; }
    (async () => {
      try {
        const doctors = await api.fetchDoctors();
        const doc = doctors.find(d => String(d.userId) === String(u.id));
        if (!doc) { setAppointments([]); setLoading(false); return; }
        const appts = await api.fetchAppointmentsByDoctor(doc.id);
        if (mounted) setAppointments(appts);
      } catch (err) { console.error(err); }
      finally { if (mounted) setLoading(false); }
    })();
    return () => mounted = false;
  }, [u]);

  const changeStatus = async (id, status) => {
    try {
      await api.setAppointmentStatus(id, status);
      setAppointments(a => a.map(x => x.id === id ? { ...x, status } : x));
    } catch (err) { alert("Failed: " + (err.message || err)); }
  };

  if (loading) return <div>Loading...</div>;
  return (
    <div style={{ maxWidth:900, margin:"20px auto", padding:12 }}>
      <h2>Doctor Dashboard</h2>
      {appointments.length === 0 && <div>No appointments.</div>}
      {appointments.map(a => (
        <div key={a.id} style={{border:"1px solid #ddd", padding:12, marginBottom:8}}>
          <div><strong>Patient:</strong> {a.patient?.name || a.patientId}</div>
          <div><strong>Time:</strong> {a.appointmentTime}</div>
          <div><strong>Reason:</strong> {a.reason}</div>
          <div><strong>Status:</strong> {a.status}</div>
          <div style={{marginTop:8}}>
            <button onClick={() => changeStatus(a.id, "ACCEPTED")} disabled={a.status === "ACCEPTED"}>Accept</button>
            <button onClick={() => changeStatus(a.id, "REJECTED")} disabled={a.status === "REJECTED"} style={{marginLeft:8}}>Reject</button>
          </div>
        </div>
      ))}
    </div>
  );
}
